import { readFile, readdir, writeFile } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const repoRoot = resolve(__dirname, '..');

const runtimeSourceFiles = [
  'src/runtime/config.js',
  'src/runtime/sources/base_source.js',
  'src/runtime/sources/nhentai.js',
  'src/runtime/url-utils.js',
  'src/runtime/cache.js',
  'src/runtime/adapters/engines/base_engine.js',
  'src/runtime/adapters/engines/webgl.js',
  'src/runtime/adapters/engines/webgpu.js',
  'src/runtime/engine.js',
  'src/runtime/dom.js',
  'src/runtime/queue.js',
  'src/runtime/orchestrator.js'
];

const outputFile = 'src/runtime/runtime.bundle.js';
const shouldCheck = process.argv.includes('--check');

async function listRuntimeSourceFilesOnDisk() {
  const runtimeRoot = resolve(repoRoot, 'src/runtime');

  async function collectJsFiles(absoluteDir, relativeDir = 'src/runtime') {
    const entries = await readdir(absoluteDir, { withFileTypes: true });
    const files = [];

    for (const entry of entries) {
      if (entry.name === '_metadata') continue;

      const absolutePath = resolve(absoluteDir, entry.name);
      const relativePath = `${relativeDir}/${entry.name}`;

      if (entry.isDirectory()) {
        const nested = await collectJsFiles(absolutePath, relativePath);
        files.push(...nested);
        continue;
      }

      if (entry.isFile() && entry.name.endsWith('.js') && relativePath !== outputFile) {
        files.push(relativePath);
      }
    }

    return files;
  }

  const discoveredFiles = await collectJsFiles(runtimeRoot);
  return new Set(discoveredFiles);
}

async function verifyRuntimeSourceCoverage() {
  const listed = new Set(runtimeSourceFiles);
  const discovered = await listRuntimeSourceFilesOnDisk();

  const missing = [...discovered].filter((filePath) => !listed.has(filePath));
  const extra = [...listed].filter((filePath) => !discovered.has(filePath));

  if (missing.length === 0 && extra.length === 0) {
    return;
  }

  if (missing.length > 0) {
    process.stderr.write(`Bundle source list is missing runtime files:\n${missing.map((p) => `- ${p}`).join('\n')}\n`);
  }

  if (extra.length > 0) {
    process.stderr.write(`Bundle source list contains files not found on disk:\n${extra.map((p) => `- ${p}`).join('\n')}\n`);
  }

  process.exitCode = 1;
  throw new Error('Runtime bundle source coverage check failed');
}

async function composeBundleContent() {
  const parts = [];
  for (const relativePath of runtimeSourceFiles) {
    const absolutePath = resolve(repoRoot, relativePath);
    const content = await readFile(absolutePath, 'utf8');
    parts.push(`// --- BEGIN ${relativePath} ---\n${content.trimEnd()}\n// --- END ${relativePath} ---\n`);
  }

  const banner = `// AUTO-GENERATED FILE - DO NOT EDIT DIRECTLY\n// Generated by tools/build-runtime-bundle.mjs\n\n`;
  return banner + parts.join('\n');
}

async function check() {
  await verifyRuntimeSourceCoverage();
  const expected = await composeBundleContent();
  let current = '';

  try {
    current = await readFile(resolve(repoRoot, outputFile), 'utf8');
  } catch {
    process.stderr.write(`${outputFile} does not exist. Run node tools/build-runtime-bundle.mjs\n`);
    process.exitCode = 1;
    return;
  }

  if (current !== expected) {
    process.stderr.write(`Runtime bundle is out of date. Run node tools/build-runtime-bundle.mjs\n`);
    process.exitCode = 1;
    return;
  }

  process.stdout.write(`Runtime bundle is up to date (${outputFile}).\n`);
}

async function build() {
  await verifyRuntimeSourceCoverage();
  const output = await composeBundleContent();
  await writeFile(resolve(repoRoot, outputFile), output, 'utf8');

  process.stdout.write(`Built ${outputFile} from ${runtimeSourceFiles.length} source files.\n`);
}

const task = shouldCheck ? check : build;

task().catch((error) => {
  process.stderr.write(`Failed to build runtime bundle: ${String(error)}\n`);
  process.exitCode = 1;
});
